        if (!timestamp) return;
        const timeForDisplay = timestamp.toLocaleTimeString('ar-EG-u-nu-latn', { timeZone, hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
        const dateString = toRiyadhDateString(timestamp);
