            const isAbsent = item.checkInTime === null && item.checkOutTime === null;
            if ((type === 'present' && !isAbsent) || (type === 'absent' && isAbsent)) {
                dateSet.add(item.date);
            }
        });

    const dates = Array.from(dateSet)
        .sort((a, b) => b.localeCompare(a))
