        'ملاحظات': item.notes || '',
      }));
      fileName = 'تقرير_حضور_المعلمين_التفصيلي.xlsx';
      sheetName = 'التقرير التفصيلي';
    } else { // summary
      dataToExport = summaryData.map(item => ({
