    </button>
  );

  const printTitle = `تقرير حضور المعلمين - ${new Date().toLocaleDateString('ar-EG')}`;

  return (
    <div className="space-y-6">
      <div className="flex justify-end print-hidden gap-2">
        {/* Refresh Button */}
        {onRefresh && (
