const TeacherAttendanceReportPage: React.FC<TeacherAttendanceReportPageProps> = ({ reportData, onRefresh, isRefreshing }) => {
  const [activeTab, setActiveTab] = React.useState<'detailed' | 'summary'>('detailed');
