const normalizeArabicForMatch = (text: string) => {
    if (!text) return '';
    return text
        .normalize('NFC')
        .replace(/[\u200B-\u200D\uFEFF]/g, '') // Remove zero-width characters
        .replace(/\s+/g, ' ') // Standardize whitespace
        .replace(/[إأآا]/g, 'ا') // Unify Alif
