                setCurrentPage('general');
            }
        }
    }, [authenticatedUser, currentPage]);

    // ... (handlePostEvaluation, handlePostExam, handlePostTeacherAttendance, handlePostSupervisorAttendance, handlePostSettings - UNCHANGED)
    const handlePostEvaluation = async (data: EvalSubmissionPayload) => {
        setIsSubmitting(true);
        setNotification(null);
        try {
            await fetch(API_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain;charset=utf-8' },
