        }
        return false;
    };

    const saveToCache = async (data: any) => {
        try {
            await saveToDB(CACHE_KEY, data);
        } catch (e) {
            console.warn("Failed to save to cache (Quota Exceeded)", e);
        }
    };

    const loadData = async () => {
        setError(null);
