    const handlePostSettings = async (data: ProcessedSettingsData) => {
        setIsSubmitting(true);
        setNotification(null);
        const originalSettings = { ...settings };
        setSettings(data);

        try {
            const updateUrl = `${API_URL}?action=updateSettings`;
