            if (page === 'settings' && authenticatedUser.role !== 'admin') {
                setNotification({ message: 'ليس لديك صلاحية للوصول إلى هذه الصفحة.', type: 'error' });
                setIsMobileSidebarOpen(false);
                return;
            }
